import React, { useEffect, useState, useMemo, useRef } from 'react';
import axios from 'axios';
import Header from './Header';
import * as XLSX from 'xlsx';
import { FaSearch, FaEllipsisV, FaFileExcel, FaBoxOpen, FaTags, FaBarcode, FaWeightHanging, FaMapMarkerAlt, FaCheckCircle } from 'react-icons/fa';

const API_URL = 'https://rrgold.loyalstring.co.in/api/ProductMaster/GetAllLabeledStock';
const PAGE_SIZE = 25;

const Inventory = ({ clientCode, userInfo }) => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [labels, setLabels] = useState([]);
  const [search, setSearch] = useState('');
  const [filters, setFilters] = useState({});
  const [page, setPage] = useState(1);
  const searchInputRef = useRef(null);
  const [selectedRows, setSelectedRows] = useState([]);

  useEffect(() => {
    if (!clientCode) return;
    setLoading(true);
    setError('');
    axios.post(API_URL, { ClientCode: clientCode })
      .then(res => {
        if (Array.isArray(res.data)) {
          setLabels(res.data);
        } else if (res.data && Array.isArray(res.data.Data)) {
          setLabels(res.data.Data);
        } else {
          setLabels([]);
        }
      })
      .catch(err => {
        setError(err.response?.data?.Message || 'Failed to fetch label list');
      })
      .finally(() => setLoading(false));
  }, [clientCode]);

  // Filtering and searching
  const filteredLabels = useMemo(() => {
    let data = labels;
    // Search
    if (search) {
      const s = search.toLowerCase();
      data = data.filter(l =>
        (l.ItemCode && l.ItemCode.toLowerCase().includes(s)) ||
        (l.ProductName && l.ProductName.toLowerCase().includes(s)) ||
        (l.BranchName && l.BranchName.toLowerCase().includes(s))
      );
    }
    // Column filters
    Object.entries(filters).forEach(([key, value]) => {
      if (value) {
        data = data.filter(l => (l[key] || '').toString().toLowerCase().includes(value.toLowerCase()));
      }
    });
    return data;
  }, [labels, search, filters]);

  // Pagination
  let paginatedLabels = filteredLabels;
  let totalPages = 1;
  if (!search) {
    totalPages = Math.ceil(filteredLabels.length / PAGE_SIZE);
    paginatedLabels = filteredLabels.slice((page - 1) * PAGE_SIZE, page * PAGE_SIZE);
  }

  // Unique values for filters
  const getUnique = (key) => [...new Set(labels.map(l => l[key]).filter(Boolean))];

  // Handle filter change
  const handleFilterChange = (key, value) => {
    setFilters(f => ({ ...f, [key]: value }));
    setPage(1);
  };

  // Handle search change
  const handleSearchChange = (e) => {
    setSearch(e.target.value);
    setPage(1);
  };

  // Handle page change
  const handlePageChange = (newPage) => {
    if (newPage >= 1 && newPage <= totalPages) setPage(newPage);
  };

  // Export to Excel
  const handleExport = () => {
    const exportData = filteredLabels.map(({ Id, ...rest }) => rest); // Remove Id if not needed
    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Inventory');
    XLSX.writeFile(wb, 'inventory.xlsx');
  };

  // Selection state
  const allSelected = paginatedLabels.length > 0 && paginatedLabels.every(l => selectedRows.includes(l.Id));
  const toggleSelectAll = () => {
    if (allSelected) setSelectedRows(selectedRows.filter(id => !paginatedLabels.some(l => l.Id === id)));
    else setSelectedRows([...new Set([...selectedRows, ...paginatedLabels.map(l => l.Id)])]);
  };
  const toggleSelectRow = (id) => {
    setSelectedRows(selectedRows.includes(id) ? selectedRows.filter(i => i !== id) : [...selectedRows, id]);
  };

  return (
    <div style={{ minHeight: '100vh', background: '#f7f8fa', fontFamily: 'Inter, sans-serif' }}>
      <Header userInfo={{ ClientCode: clientCode, Username: userInfo?.Username || '' }} />
      <div className="container py-4" style={{ maxWidth: 1500 }}>
        {/* Title */}
        <div className="text-center pt-8 pb-4">
          <h1 style={{
            fontWeight: 800,
            fontSize: '2.5rem',
            borderBottom: '3px solid #e5e7eb',
            display: 'inline-block',
            paddingBottom: 8,
            marginBottom: 0,
            letterSpacing: 0.5,
          }}>
            Inventory Labelled List
          </h1>
        </div>
        {/* Top bar */}
        <div className="d-flex flex-wrap align-items-center justify-content-between mb-6 px-2" style={{ maxWidth: 1300, margin: '0 auto' }}>
          {/* Search */}
          <div className="d-flex align-items-center" style={{ flex: 1 }}>
            <div style={{ position: 'relative', width: 320 }}>
              <input
                type="text"
                placeholder="Search..."
                value={search}
                onChange={handleSearchChange}
                style={{
                  borderRadius: 9999,
                  border: '1.5px solid #e5e7eb',
                  padding: '10px 16px 10px 40px',
                  width: 320,
                  boxShadow: '0 1px 4px #0001',
                  fontSize: '1.08rem',
                  background: '#fff',
                }}
              />
              <span style={{
                position: 'absolute', left: 14, top: '50%', transform: 'translateY(-50%)',
                color: '#9ca3af', fontSize: 20
              }}>
                <FaSearch />
              </span>
            </div>
          </div>
          {/* Export */}
          <button
            onClick={handleExport}
            style={{
              border: '1.5px solid #22bb33',
              color: '#22bb33',
              background: '#e6f9ed',
              borderRadius: 8,
              fontWeight: 600,
              height: 44,
              fontSize: '1.08rem',
              padding: '0 22px',
              marginLeft: 16,
              display: 'flex',
              alignItems: 'center',
              transition: 'background 0.2s',
            }}
            onMouseOver={e => e.currentTarget.style.background = '#d1fae5'}
            onMouseOut={e => e.currentTarget.style.background = '#e6f9ed'}
          >
            <FaFileExcel className="me-2" /> Export to Excel
          </button>
        </div>
        {/* Table */}
        <div className="overflow-x-auto" style={{ maxWidth: 1300, margin: '32px auto', background: '#fff', borderRadius: 18, boxShadow: '0 6px 32px #0002', padding: 0 }}>
          <table className="table align-middle mb-0" style={{ width: '100%', minWidth: 1100, background: '#fff', borderRadius: 18, overflow: 'hidden', borderCollapse: 'separate', borderSpacing: 0, fontSize: '1.12rem' }}>
            <thead style={{ background: '#fff', borderTopLeftRadius: 18, borderTopRightRadius: 18, boxShadow: '0 2px 8px #0001' }}>
              <tr style={{ borderRadius: 18, height: 60 }}>
                <th style={{ width: 70, background: '#fff', border: 'none', padding: '0 10px', fontWeight: 700, fontSize: '1.12rem' }}>Sr No</th>
                <th style={{ fontWeight: 700, color: '#222', background: '#fff', fontSize: '1.12rem', padding: '16px 14px', border: 'none', minWidth: 180 }}>Product Name</th>
                <th style={{ fontWeight: 700, color: '#222', background: '#fff', fontSize: '1.12rem', padding: '16px 14px', border: 'none', minWidth: 120 }}>Category</th>
                <th style={{ fontWeight: 700, color: '#222', background: '#fff', fontSize: '1.12rem', padding: '16px 14px', border: 'none', minWidth: 120 }}>SKU</th>
                <th style={{ fontWeight: 700, color: '#222', background: '#fff', fontSize: '1.12rem', padding: '16px 14px', border: 'none', minWidth: 120 }}>Gross Wt</th>
                <th style={{ fontWeight: 700, color: '#222', background: '#fff', fontSize: '1.12rem', padding: '16px 14px', border: 'none', minWidth: 120 }}>Net Wt</th>
                <th style={{ fontWeight: 700, color: '#222', background: '#fff', fontSize: '1.12rem', padding: '16px 14px', border: 'none', minWidth: 120 }}>Branch</th>
                <th style={{ fontWeight: 700, color: '#222', background: '#fff', borderTopRightRadius: 18, fontSize: '1.12rem', padding: '16px 14px', border: 'none', minWidth: 120 }}>Status</th>
              </tr>
              {/* Filter Row */}
              <tr style={{ background: '#f9fafb' }}>
                <td></td>
                <td><select className="form-select form-select-sm" style={{ borderRadius: 8, padding: '4px 8px', fontSize: '0.98rem', border: '1.5px solid #e5e7eb', outline: 'none' }} value={filters.ProductName || ''} onChange={e => handleFilterChange('ProductName', e.target.value)}><option value="">All</option>{getUnique('ProductName').map(val => <option key={val} value={val}>{val}</option>)}</select></td>
                <td><select className="form-select form-select-sm" style={{ borderRadius: 8, padding: '4px 8px', fontSize: '0.98rem', border: '1.5px solid #e5e7eb', outline: 'none' }} value={filters.CategoryName || ''} onChange={e => handleFilterChange('CategoryName', e.target.value)}><option value="">All</option>{getUnique('CategoryName').map(val => <option key={val} value={val}>{val}</option>)}</select></td>
                <td><select className="form-select form-select-sm" style={{ borderRadius: 8, padding: '4px 8px', fontSize: '0.98rem', border: '1.5px solid #e5e7eb', outline: 'none' }} value={filters.ItemCode || ''} onChange={e => handleFilterChange('ItemCode', e.target.value)}><option value="">All</option>{getUnique('ItemCode').map(val => <option key={val} value={val}>{val}</option>)}</select></td>
                <td><select className="form-select form-select-sm" style={{ borderRadius: 8, padding: '4px 8px', fontSize: '0.98rem', border: '1.5px solid #e5e7eb', outline: 'none' }} value={filters.GrossWt || ''} onChange={e => handleFilterChange('GrossWt', e.target.value)}><option value="">All</option>{getUnique('GrossWt').map(val => <option key={val} value={val}>{val}</option>)}</select></td>
                <td><select className="form-select form-select-sm" style={{ borderRadius: 8, padding: '4px 8px', fontSize: '0.98rem', border: '1.5px solid #e5e7eb', outline: 'none' }} value={filters.NetWt || ''} onChange={e => handleFilterChange('NetWt', e.target.value)}><option value="">All</option>{getUnique('NetWt').map(val => <option key={val} value={val}>{val}</option>)}</select></td>
                <td><select className="form-select form-select-sm" style={{ borderRadius: 8, padding: '4px 8px', fontSize: '0.98rem', border: '1.5px solid #e5e7eb', outline: 'none' }} value={filters.BranchName || ''} onChange={e => handleFilterChange('BranchName', e.target.value)}><option value="">All</option>{getUnique('BranchName').map(val => <option key={val} value={val}>{val}</option>)}</select></td>
                <td><select className="form-select form-select-sm" style={{ borderRadius: 8, padding: '4px 8px', fontSize: '0.98rem', border: '1.5px solid #e5e7eb', outline: 'none' }} value={filters.Status || ''} onChange={e => handleFilterChange('Status', e.target.value)}><option value="">All</option>{getUnique('Status').map(val => <option key={val} value={val}>{val}</option>)}</select></td>
              </tr>
            </thead>
            <tbody>
              {paginatedLabels.map((label, idx) => (
                <tr key={label.Id} style={{ background: idx % 2 === 0 ? '#f7f7f7' : '#fff', transition: 'background 0.2s', cursor: 'pointer', borderBottom: '1.5px solid #e0e0e0', height: 60 }}
                  onMouseOver={e => e.currentTarget.style.background = '#f0f0f0'}
                  onMouseOut={e => e.currentTarget.style.background = idx % 2 === 0 ? '#f7f7f7' : '#fff'}
                >
                  <td style={{ width: 70, border: 'none', padding: '0 10px', fontWeight: 600, textAlign: 'center' }}>{(page - 1) * 25 + idx + 1}</td>
                  <td style={{ fontWeight: 500, color: '#222', letterSpacing: 0.2, padding: '16px 12px', border: 'none', minWidth: 180 }}>{label.ProductName}</td>
                  <td style={{ padding: '16px 12px', border: 'none', minWidth: 120 }}>{label.CategoryName}</td>
                  <td style={{ padding: '16px 12px', border: 'none', minWidth: 120 }}>{label.ItemCode}</td>
                  <td style={{ padding: '16px 12px', border: 'none', minWidth: 120 }}>{label.GrossWt}</td>
                  <td style={{ padding: '16px 12px', border: 'none', minWidth: 120 }}>{label.NetWt}</td>
                  <td style={{ padding: '16px 12px', border: 'none', minWidth: 120 }}>{label.BranchName}</td>
                  <td style={{ padding: '16px 12px', border: 'none', minWidth: 120 }}>
                    <span className={`badge`} style={{ background: label.Status === 'Active' ? '#e6f9ed' : '#ffeaea', color: label.Status === 'Active' ? '#22bb33' : '#e74c3c', fontWeight: 600, fontSize: '1em', padding: '7px 18px', borderRadius: 16, border: 'none' }}>{label.Status}</span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {/* Pagination */}
        {totalPages > 1 && !search && (
          <div className="d-flex justify-content-center align-items-center mt-4 overflow-x-auto flex-nowrap whitespace-nowrap" style={{ maxWidth: 600, margin: '0 auto' }}>
            <nav>
              <ul className="pagination mb-0" style={{ background: '#fff', borderRadius: 10, boxShadow: '0 1px 6px #0001', padding: '10px 24px', display: 'flex', flexWrap: 'nowrap', gap: 4 }}>
                <li className={`page-item${page === 1 ? ' disabled' : ''}`}><button className="page-link" style={{ border: 'none', background: 'none', color: '#2563eb', fontWeight: 600, fontSize: '1.15rem', borderRadius: 8, padding: '6px 16px' }} onClick={() => handlePageChange(page - 1)}>&laquo;</button></li>
                {[...Array(totalPages)].map((_, idx) => (
                  <li key={idx} className={`page-item${page === idx + 1 ? ' active' : ''}`}>
                    <button className="page-link" style={{ border: 'none', background: idx + 1 === page ? '#2563eb' : 'none', color: idx + 1 === page ? '#fff' : '#2563eb', fontWeight: 600, fontSize: '1.15rem', borderRadius: 8, margin: '0 3px', minWidth: 38, padding: '6px 16px' }} onClick={() => handlePageChange(idx + 1)}>{idx + 1}</button>
                  </li>
                ))}
                <li className={`page-item${page === totalPages ? ' disabled' : ''}`}><button className="page-link" style={{ border: 'none', background: 'none', color: '#2563eb', fontWeight: 600, fontSize: '1.15rem', borderRadius: 8, padding: '6px 16px' }} onClick={() => handlePageChange(page + 1)}>&raquo;</button></li>
              </ul>
            </nav>
          </div>
        )}
      </div>
    </div>
  );
};

export default Inventory;
